        materials.filter(Boolean).forEach((material) => material.dispose());
      });
      renderer?.dispose();
    };
  }, [entry]);

  return (
    <canvas
      ref={canvasRef}
      width={64}
      height={64}
      aria-hidden="true"
      data-testid="asset-rendered-thumbnail"
      style={{ display: 'block', width: 56, height: 56 }}
    />
  );
